def predict_next_frame(frame, action, xy=None):
    # Create a deep copy of the frame to avoid modifying the original
    new_frame = [row[:] for row in frame]

    # Define action mappings
    if action == "ACTION1":
        # Fill entire grid with color 14
        for i in range(64):
            for j in range(64):
                new_frame[i][j] = 14
    elif action == "ACTION2":
        # Fill entire grid with color 5
        for i in range(64):
            for j in range(64):
                new_frame[i][j] = 5
    elif action == "ACTION3":
        # Fill entire grid with color 10
        for i in range(64):
            for j in range(64):
                new_frame[i][j] = 10
    elif action == "ACTION4":
        # Fill entire grid with color 9
        for i in range(64):
            for j in range(64):
                new_frame[i][j] = 9
    elif action == "ACTION5":
        # Fill entire grid with color 2
        for i in range(64):
            for j in range(64):
                new_frame[i][j] = 2
    elif action == "ACTION6":
        if xy is not None:
            x, y = xy
            # Get the current color at the clicked position
            current_color = frame[y][x]
            # Change all cells of that color to color 15
            for i in range(64):
                for j in range(64):
                    if new_frame[i][j] == current_color:
                        new_frame[i][j] = 15
    elif action == "ACTION7":
        # Fill entire grid with color 11
        for i in range(64):
            for j in range(64):
                new_frame[i][j] = 11

    return new_frame

